use data::*;

macro_rules! implies {
  ($lhs: expr, $rhs: expr) => {
    !$lhs || $rhs
  };
}

macro_rules! impliesL {
  ($lhs: expr, $rhs: expr) => {
    !$lhs | $rhs
  };
}

/** Compute Entrypoint Contract
  *
  * assumes a1
  * @param api_read_port1 incoming event port
  * @param api_read_port2 incoming event port
  */
pub fn compute_spec_a1_assume(
  api_read_port1: Option<u8>,
  api_read_port2: Option<u8>) -> bool
{
  implies!(
    api_read_port1.is_some(),
    !(api_read_port2.is_some()))
}

/** CEP-T-Assm: Top-level assume contracts for consumer's compute entrypoint
  *
  * @param api_read_port1 incoming event port
  * @param api_read_port2 incoming event port
  */
pub fn compute_CEP_T_Assm(
  api_read_port1: Option<u8>,
  api_read_port2: Option<u8>) -> bool
{
  let r0: bool = compute_spec_a1_assume(api_read_port1, api_read_port2);

  return r0;
}

/** CEP-Pre: Compute Entrypoint Pre-Condition for consumer
  *
  * @param api_read_port1 incoming event port
  * @param api_read_port2 incoming event port
  */
pub fn compute_CEP_Pre(
  api_read_port1: Option<u8>,
  api_read_port2: Option<u8>) -> bool
{
  // CEP-Assm: assume clauses of consumer's compute entrypoint
  let r0: bool = compute_CEP_T_Assm(api_read_port1, api_read_port2);

  return r0;
}
